import{_ as a,o as n,c as r,ag as t}from"./chunks/framework.CAXxHpAX.js";const f=JSON.parse('{"title":"Fase 8: Multi-tenancy governance & SLA-framework","description":"","frontmatter":{"title":"Fase 8: Multi-tenancy governance & SLA-framework","phase":8,"topic":"governance","personas":["leder"],"tags":["SLA","governance","KPI","onboarding","offboarding","service-review"],"priority":"parallel","dependencies":[]},"headers":[],"relativePath":"faser/08-governance.md","filePath":"faser/08-governance.md"}'),s={name:"faser/08-governance.md"};function o(i,e,l,d,g,p){return n(),r("div",null,[...e[0]||(e[0]=[t('<h1 id="fase-8-multi-tenancy-governance-sla-framework" tabindex="-1">Fase 8: Multi-tenancy governance &amp; SLA-framework <a class="header-anchor" href="#fase-8-multi-tenancy-governance-sla-framework" aria-label="Permalink to &quot;Fase 8: Multi-tenancy governance &amp; SLA-framework&quot;">​</a></h1><div class="phase-meta"><span><strong>Sti:</strong> <span class="parallel-badge">Parallel</span></span><span><strong>Afhænger af:</strong> Ingen — kan starte fra dag 1</span><span><strong>Skal være klar inden:</strong> Fase 9</span></div><div class="persona-badges"><span class="persona-badge leder">📊 IT-leder</span></div><p>Det forventes, at governance-modellen for multi-tenant-driften er dokumenteret og aftalt med alle parter før den første kommune onboardes. Modellen skal sikre gennemsigtighed, ligebehandling og klar ansvarsfordeling.</p><ul><li><p>SLA&#39;er defineres pr. tenant og kritikalitetsklasse med målbare KPI&#39;er for oppetid, performance, responstid og genopretning.</p></li><li><p>Governance-model dokumenterer ansvar, eskalering, beslutningskompetence og kommunikationskanaler for den fælles driftsorganisation og de individuelle tenants.</p></li><li><p>Automatiseret SLA-monitorering med realtids-dashboards og proaktiv alarmering ved potentielle SLA-brud etableres.</p></li><li><p>Regelmæssige service reviews med tenant-repræsentanter planlægges for gennemgang af SLA-performance, hændelser og forbedringsinitiativer.</p></li><li><p>Standardiseret onboarding- og offboarding-proces dokumenteres med definerede faser, kvalitetskriterier og ansvarsfordeling.</p></li></ul>',5)])])}const m=a(s,[["render",o]]);export{f as __pageData,m as default};
